import React, { useEffect, useState } from 'react';
import { useTrail, animated } from '@react-spring/web';
import Icon from './Icon';
import icons from '../config/iconContacts';

interface ContactsProps {
  toggle: boolean;
}

const Contacts = ({ toggle }: ContactsProps) => {
  const contactsAnim = useTrail(icons.length, {
    from: {
      opacity: 0,
      transform: 'translateX(150px)',
      display: 'none' as const,
    },
    to: {
      opacity: toggle ? 1 : 0,
      transform: toggle ? 'translateX(0px)' : 'translateX(150px)',
      display: 'block' as const,
    },
    config: { mass: 0.4, tension: 500, friction: 20 },
    delay: 200,
  });

  const [display, setDisplay] = useState(false);

  useEffect(() => {
    if (toggle && !display) {
      setDisplay(true);
    }
    if (!toggle && display) {
      setTimeout(() => {
        setDisplay(false);
      }, 500);
    }
  }, [toggle, display]);

  return (
    <div className="relative -right-[110px] top-0 flex h-[100px] w-[230px] items-center justify-between p-[5px] max-[750px]:-right-10 max-[750px]:top-[-15px] max-[750px]:h-[50px] max-[750px]:w-[150px]">
      {display &&
        contactsAnim.map((styles, index) => (
          <animated.div key={index} style={styles}>
            <Icon
              name={icons[index].name}
              title={icons[index].title}
              url={icons[index].url}
            />
          </animated.div>
        ))}
    </div>
  );
};

export default Contacts;
